const body = $json.body ?? $json;
const type = (body.type ?? '').toString().toLowerCase();

if (type !== 'student_progress_snapshot') {
  return [{
    json: {
      status: 'rejected',
      reason: 'unsupported_type',
      expectedType: 'student_progress_snapshot',
      receivedType: type || 'unknown',
      session: 'system',
      receivedAt: new Date().toISOString()
    }
  }];
}

const student = body.student ?? {};
const level = Number(student.level ?? 0);
const xp = Number(student.xp ?? 0);
const completedNodes = Array.isArray(student.completedNodes) ? student.completedNodes : [];
const unlockedNodes = Array.isArray(student.unlockedNodes) ? student.unlockedNodes : [];
const selectedSeed = student.selectedSeed ?? null;

const state = {
  userId: student.userId ?? null,
  selectedSeed,
  level,
  xp,
  completedCount: completedNodes.length,
  unlockedCount: unlockedNodes.length,
  completedNodes,
  unlockedNodes
};

const issues = [];
if (!selectedSeed) issues.push('seed_missing');
if (completedNodes.length > unlockedNodes.length) issues.push('completed_gt_unlocked');
if (level < 0 || xp < 0) issues.push('negative_progress');

return [{
  json: {
    status: 'accepted',
    session: 'system',
    eventType: 'student_progress_snapshot',
    state,
    issues,
    guard: {
      progressionStateTrusted: issues.length === 0,
      stateVersion: 'v1'
    },
    receivedAt: new Date().toISOString()
  }
}];
